mapper.select:
SELECT COUNT(*)
FROM stocks
WHERE item_id = #{itemId}

mapper.update:
UPDATE stocks
SET status = #{status}
WHERE id = #{id}
  AND status = 'IN_STOCK'

mapper.delete:
DELETE FROM stocks
WHERE external_id = #{externalId}
  AND status = 'IN_STOCK'
  AND item_id IN (
      SELECT id
      FROM items
      WHERE user_id = #{userId}
  )

DELETE FROM stocks
WHERE item_id = #{itemId}
  AND box_id  = #{boxId}
  AND status  = 'IN_STOCK'

DELETE FROM stocks
WHERE item_id  = #{itemId}
  AND shelf_id = #{shelfId}
  AND box_id IS NULL
  AND status   = 'IN_STOCK'

DELETE FROM stocks
WHERE item_id  = #{itemId}
  AND space_id = #{spaceId}
  AND shelf_id IS NULL
  AND status   = 'IN_STOCK'

mapper.select:

WHERE i.user_id = #{userId}
  AND s.status = 'IN_STOCK'

  AND i.external_id = #{itemExternalId}


  AND sp.external_id = #{spaceExternalId}


  AND sh.external_id = #{shelfExternalId}


  AND b.external_id = #{boxExternalId}

ORDER BY i.name, sp.name, sh.name, b.name, s.created_at DESC

